738	            EP_HOST_ASSERT(cached_num_expanded_tokens.has_value());
739	            EP_HOST_ASSERT(cached_psum_num_recv_tokens_per_scaleup_rank.has_value());
740	            EP_HOST_ASSERT(cached_psum_num_recv_tokens_per_expert.has_value());
741	            EP_HOST_ASSERT(cached_dst_buffer_slot_idx.has_value());
742	
743	            // Hybrid kernels require more
744	            if (nccl_context->num_scaleout_ranks > 1) {
745	                EP_HOST_ASSERT(cached_token_metadata_at_forward.has_value());
746	                EP_HOST_ASSERT(cached_channel_linked_list.has_value());
747	            }
748	        }
749	
750	        // Check data tensor
751	        const auto [num_tokens, hidden] = get_shape<2>(x);
752	        const auto num_hidden_bytes = hidden * static_cast<int>(x.element_size());
753	        const auto num_local_experts = num_experts / nccl_context->num_ranks;
754	        EP_HOST_ASSERT(x.is_cuda() and x.is_contiguous());
755	        EP_HOST_ASSERT((x.size(1) * x.element_size()) % sizeof(int4) == 0);
756	        EP_HOST_ASSERT(num_tokens <= num_max_tokens_per_rank);
757	
758	        // Check SF stuffs
759	        int num_sf_packs = 0;
760	        void* sf_ptr = nullptr;
761	        int sf_token_stride = 0, sf_hidden_stride = 0;
762	        if (sf.has_value()) {
763	            // SF must be FP32 or packed UE8M0x4
764	            const auto [num_tokens_, num_sf_packs_] = get_shape<2>(sf.value());
765	            EP_HOST_ASSERT(num_tokens == num_tokens_);
766	            EP_HOST_ASSERT(sf->is_cuda());
767	            EP_HOST_ASSERT(sf->element_size() == sizeof(sf_pack_t));
