774	        // Check top-k stuffs
775	        const auto [num_tokens_, num_topk] = get_shape<2>(topk_idx);
776	        EP_HOST_ASSERT(num_tokens == num_tokens_);
777	        EP_HOST_ASSERT(topk_idx.scalar_type() == c10::CppTypeToScalarType<topk_idx_t>::value);
778	        EP_HOST_ASSERT(topk_idx.is_cuda() and topk_idx.is_contiguous());
779	
780	        // Weights are optional for training backward
781	        float* topk_weights_ptr = nullptr;
782	        if (topk_weights.has_value()) {
783	            const auto [num_tokens__, num_topk_] = get_shape<2>(topk_weights.value());
784	            EP_HOST_ASSERT(num_tokens == num_tokens__);
785	            EP_HOST_ASSERT(topk_weights->is_cuda() and topk_weights->is_contiguous());
786	            topk_weights_ptr = topk_weights->data_ptr<float>();
787	        }
788	
789	        // Expert receiving counter
790	        int* cumulative_local_expert_recv_stats_ptr = nullptr;
791	        if (cumulative_local_expert_recv_stats.has_value()) {
792	            const auto [num_local_experts_] = get_shape<1>(cumulative_local_expert_recv_stats.value());
793	            EP_HOST_ASSERT(cumulative_local_expert_recv_stats->is_cuda() and
794	                           cumulative_local_expert_recv_stats->is_contiguous());
795	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
796	            cumulative_local_expert_recv_stats_ptr = cumulative_local_expert_recv_stats->data_ptr<int>();
797	        }
798	
799	        // Stream control
800	        // All new tensor allocations should happen after this
801	        const auto compute_stream = stream_control_prologue(previous_event, allocate_on_comm_stream, async_with_compute_stream);
802	
803	        // The number of received tokens per expert
804	        // This is useful for expanding mode
805	        EP_HOST_ASSERT(num_experts % nccl_context->num_ranks == 0);
806	        auto psum_num_recv_tokens_per_expert = cached_psum_num_recv_tokens_per_expert.value_or(torch::Tensor());
807	        if (cached_mode) {
808	            const auto& [num_local_experts_] = get_shape<1>(psum_num_recv_tokens_per_expert);
809	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
810	            EP_HOST_ASSERT(psum_num_recv_tokens_per_expert.is_cuda() and psum_num_recv_tokens_per_expert.is_contiguous());
