818	        // The unaligned (actual) number of received tokens per expert
819	        // Written by the dispatch kernel's notify warps, used by the epilogue for zero padding
820	        auto num_unaligned_recv_tokens_per_expert = cached_num_unaligned_recv_tokens_per_expert.value_or(torch::Tensor());
821	        int* num_unaligned_recv_tokens_per_expert_ptr = nullptr;
822	        if (cached_mode) {
823	            const auto& [num_local_experts_] = get_shape<1>(num_unaligned_recv_tokens_per_expert);
824	            EP_HOST_ASSERT(num_local_experts == num_local_experts_);
825	            EP_HOST_ASSERT(num_unaligned_recv_tokens_per_expert.is_cuda() and num_unaligned_recv_tokens_per_expert.is_contiguous());
826	            EP_HOST_ASSERT(num_unaligned_recv_tokens_per_expert.scalar_type() == torch::kInt);
827	        } else {
